    const codeOptions = [
        {
            method: "getGridCombo",
            param1: "OP199",
            param2: 2,
            param3: "1",
            param4: true,
            compID: "sbx_OP199_Combo01"
        },
        {
            method: "getGridComboByUpperCd",
            param1: "OP199",
            param2: "J",
            param3: true,
            compID: "sbx_OP199_Combo02"
        }
    ];
    $c.data.setGauceUtil(codeOptions, scwin.commonCodeCallBack01);
};

