scwin.initSetVal = function() {
    scwin.parentObj = $p.getFrame().getScopeWindow();
    scwin.gv_rowPos6 = 0;
    scwin.gv_rowPos7 = 0;

    scwin.tranFlag01 = false;
    scwin.tranFlag02 = false;
    scwin.tranFlag03 = false;
    scwin.tranFlag04 = false;
};

scwin.commonCodeCallBack01 = async function() {
    let ds_obj01 = $p.getComponentById(sbx_OP199_Combo01.getDataListInfo().id);

    $c.gus.cfCopyDataSetHeader(ds_obj01, ds_gr_main6_tformEqKndCd);
    ds_gr_main6_tformEqKndCd.setJSON(ds_obj01.getAllJSON(), false);
    ds_gr_main6_tformEqKndCd.insertRow(0);

    $c.gus.cfCopyDataSetHeader(ds_gr_main6_tformEqKndCd, ds_gr_main7_tformWrkImpleKndCd);
    ds_gr_main7_tformWrkImpleKndCd.setJSON(ds_gr_main6_tformEqKndCd.getAllJSON(), false);

    let ds_obj02 = $p.getComponentById(sbx_OP199_Combo02.getDataListInfo().id);

    $c.gus.cfCopyDataSetHeader(ds_obj02, ds_gr_main8_wrkImpleKndCd);
    ds_gr_main8_wrkImpleKndCd.setJSON(ds_obj02.getAllJSON(), false);

    await scwin.f_OnLoad();
};

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.f_OnLoad = async function() {
    await scwin.f_comboWrkStpCd();
    await scwin.f_defaultValue();
    await scwin.f_defaultValue2();
    await scwin.f_defaultValue3();

    scwin.interval01 = setInterval(async function() {
        if(scwin.tranFlag01 == true && scwin.tranFlag02 == true &&
           scwin.tranFlag03 == true && scwin.tranFlag04 == true) {
                clearInterval(scwin.interval01);
                $c.gus.cfEnableObj(acb_wrkIndictNo,false);
	            $c.gus.cfEnableObj(btn_no1,false);

                if (scwin.parentObj.scwin.PcvsslMgntNo != "" && scwin.parentObj.scwin.PwrkDt != "" && scwin.parentObj.scwin.PshiftClsCd != "") {
                    await scwin.parentObj.scwin.f_Retrieve();
                }
        }
    }, 100);
};



