//-------------------------------------------------------------------------
// 중복체크
//-------------------------------------------------------------------------
scwin.isGrdDupDataFlag = async function (grdObj, strGrdNm, colObj) {
    var sRtn = false;

    let hVal = "",
        tHval = "";
    let dataListObj = $p.getComponentById(grdObj.getDataList());

    // alert 출력을 위해서 헤더 정보값을 만든다
    for (let idx in colObj) {
        hVal = grdObj.getHeaderValue(grdObj.getHeaderID(grdObj.getColumnIndex(colObj[idx]))) || "이름없음";
        hVal = hVal.replace(/<[^>]*>/gi, "").replace(" ","");
        if(tHval.length == 0) {
            tHval = hVal;
        } else {
            tHval = tHval + ", " + hVal;
        }
    }

    // 배열에 컬럼값들 합쳐서 담기.
    let colData,rowData;
    let colChkAllData = [];
    for(var i=0;i<dataListObj.getRowCount();i++) {
        rowData = "";
        for (let idx in colObj) {
            colData = dataListObj.getCellData(i, colObj[idx]);
            if(idx == 0) {
                rowData = colData;
            } else {
                rowData = rowData + colData;
            }  
        }
        colChkAllData.push(rowData);
    }

    // 데이터 중복 체크
    const result = {};
    let dupIdx;
    sRtn =  colChkAllData.some((value, key) => {
                result[value] = (result[value] || 0) + 1;
                if (result[value] > 1) {
                    dupIdx = key+1;
                    return true;
                }
            });

    if (sRtn && (dupIdx != undefined && dupIdx != null && dupIdx != "")) {
        await $c.win.alert(strGrdNm + "의 " + dupIdx + "번째 데이터에서 " + tHval + "은(는) 중복될 수 없습니다.");
        scwin.sleep(50).then(function () {
            if(gr_oilUnitPrice.getFocusedColumnID() != undefined && gr_oilUnitPrice.getFocusedColumnID() != null && gr_oilUnitPrice.getFocusedColumnID() != "") {
                grdObj.setFocusedCell(dupIdx-1, gr_oilUnitPrice.getFocusedColumnID());
            } else {
                grdObj.setFocusedCell(dupIdx-1, colObj[colObj.length-1]);
            }            
        });
    }

    return sRtn;
};



//-------------------------------------------------------------------------
// Main저장 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_main6Save = async function() {
    if (ds_main6.getModifiedIndex().length == 0 && ds_main7.getModifiedIndex().length == 0 && ds_main8.getModifiedIndex().length == 0) {
  		await $c.gus.cfAlertMsg(MSG_CM_ERR_001,["중기투입계획"]); // "@은(는) 변경된 사항이 없습니다."
  		return;
  	}

	// 검색조건 필수 입력 체크
    let ret = await $c.gus.cfValidate([gr_main6]);
    if (!ret) {
        return false;
    }

    ret = await $c.gus.cfValidate([gr_main7]);
    if (!ret) {
        return false;
    }

    ret = await $c.gus.cfValidate([gr_main8]);
    if (!ret) {
        return false;
    }

    ret = await scwin.isGrdDupDataFlag(gr_main6, "중기투입계획", ["vehclShortCd"])
    if(ret) {
        return false;
    }

	for(var i=0; i<ds_main6.getRowCount(); i++){
		// 협력업체명 != '자사' : 거래처번호 필수 입력 	
		if ("자사" != ds_main6.getCellData(i,"clntNm")){
  			if (ds_main6.getCellData(i,"clntNo") == "" ) {
			    await $c.gus.cfAlertMsg("협력업체가 '자사'가 아닐 경우 거래처번호는 필수 입력 입니다.");	// "협력업체가 '자사'일 경우 거래처번호는 필수 입력 입니다."
			    gr_main6.setFocusedCell(i, "clntNo");
  				return;
			}
		} else {
			if (ds_main6.getCellData(i,"drvStaffNo1") == "" ) {
				await $c.gus.cfAlertMsg("협력업체가 '자사'일 경우 기사인원번호1은 필수 입력 입니다.");
                gr_main6.setFocusedCell(i, "drvStaffNo1");
  				return;
			}
			if (ds_main6.getCellData(i,"drvStaffNm1") == "" ) {
				await $c.gus.cfAlertMsg("협력업체가 '자사'일 경우 성명1은 필수 입력 입니다.");
                gr_main6.setFocusedCell(i, "drvStaffNo1");
  				return;
			}
		}
	}

	for(var i=0; i<ds_main7.getRowCount(); i++){
		if (ds_main7.getCellData(i,"clntNo").trim() == "" || ds_main7.getCellData(i,"clntNm").trim() == ""){
		    await $c.gus.cfAlertMsg("협력업체를 입력하시오.");	// "협력업체를 입력하시오."
            gr_main7.setFocusedCell(i, "clntNm");
			return;
		}
		// 1 > '배정대수' : 배정대수 필수 입력 	
		if (1 > Number(ds_main7.getCellData(i,"reqHveqCnt"))){
		    await $c.gus.cfAlertMsg("협력업체의 배정대수를 입력하시오.");	// "협력업체의 배정대수를 입력하시오."
            gr_main7.setFocusedCell(i, "reqHveqCnt");
			return;
		}

		if (ds_main7.getCellData(i,"wrkStpCd").trim() == "") {
			await $c.gus.cfAlertMsg("작업단계를 입력하시오.");	// "작업단계를 입력하시오."
            gr_main7.setFocusedCell(i, "wrkStpCd");
			return;
		}
	}


	for(var i=0; i<ds_main8.getRowCount(); i++) {
		if (ds_main8.getCellData(i,"wrkImpleNrmCd") == "") {
			await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["작업도구규격"]);
            gr_main8.setFocusedCell(i, "wrkImpleNrmCd");
			return;
		}
		if (1 > Number(ds_main8.getCellData(i,"wrkImpleInputCnt"))){
		    await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["투입수량"]);
            gr_main8.setFocusedCell(i, "wrkImpleInputCnt");
			return;
		}
	}

    let sRtn = await scwin.f_validateWrkTime();

	if(!sRtn){	// 시작, 종료 선후관계 Check
        /*
		if("gr_main6" == document.all.txt_hfocus.value){
			location.href = '#a_main6';
			gr_main6.Focus();
		}else{
			location.href = '#a_main7';
			gr_main7.Focus();
		}
        */
		return false;
	}

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_save);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_save_submitdone();
    }
};

scwin.sbm_save_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    scwin.f_Retrieve();
};


