    dma_search.set("wrkIndictNo", scwin.parentObj.txtWrkIndictNo.getValue());

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_search2);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_search2_submitdone();
    }
};

scwin.sbm_search2_submitdone = async function (e) {
};


//-------------------------------------------------------------------------
// 주간 Shift 계획 불러오기 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_search = async function () {
    if (txt_wrkIndictNo.getValue() == "") {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_018, ["작업지시번호","작업지시번호 생성"]); //"@이(가) 존재하지 않습니다.\n먼저 @을(를) 하십시오."
		return;
	}

    var wrkIndictNo = acb_wrkIndictNo.getValue();
    dma_search.set("wrkIndictNo", wrkIndictNo);

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_search);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_search_submitdone();
    }
};

scwin.sleep = function(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

//for=tr_search event=OnSuccess()
scwin.sbm_search_submitdone = async function (e) {
    for (var i=0; i<ds_main6.getRowCount(); i++) {
		txt_wrkIndictNo.setValue(scwin.parentObj.txtWrkIndictNo.getValue());
		ds_main6.setCellData(i,"wrkIndictNo", txt_wrkIndictNo.getValue());
		ds_main6.setCellData(i,"wrkStDt", scwin.parentObj.ica_wrkStDt.getValue());
		ds_main6.setCellData(i,"wrkStHh", scwin.parentObj.ed_wrkStHh.getValue());
		ds_main6.setCellData(i,"wrkEndDt", scwin.parentObj.ica_wrkEndDt.getValue());
		ds_main6.setCellData(i,"wrkEndHh", scwin.parentObj.ed_wrkEndHh.getValue());
	}
    /*
	var dataset = ds_main6.ExportData(1,ds_main6.CountRow,true);
	ds_main6.ClearData();
	ds_main6.ImportData(dataset);
    */

	for (var i=0; i<ds_main7.getRowCount(); i++) {
		txt_wrkIndictNo.setValue(scwin.parentObj.txtWrkIndictNo.getValue());
		ds_main7.setCellData(i,"wrkIndictNo", txt_wrkIndictNo.getValue());
		ds_main7.setCellData(i,"wrkStDt", scwin.parentObj.ica_wrkStDt.getValue());
		ds_main7.setCellData(i,"wrkStHh", scwin.parentObj.ed_wrkStHh.getValue());
		ds_main7.setCellData(i,"wrkEndDt", scwin.parentObj.ica_wrkEndDt.getValue());
		ds_main7.setCellData(i,"wrkEndHh", scwin.parentObj.ed_wrkEndHh.getValue());
	}

    /*
	var dataset = ds_main7.ExportData(1,ds_main7.CountRow,true);
	ds_main7.ClearData();
	ds_main7.ImportData(dataset);
    */

	for (var i=0; i<ds_main8.getRowCount(); i++) {
		txt_wrkIndictNo.setValue(scwin.parentObj.txtWrkIndictNo.getValue());
		ds_main8.setCellData(i,"wrkIndictNo", txt_wrkIndictNo.getValue());
	}

    /*
	var dataset = ds_main8.ExportData(1,ds_main8.CountRow,true);
	ds_main8.ClearData();
	ds_main8.ImportData(dataset);
    */

	if(ds_main6.getRowCount() > 0){
        ds_main6.modifyAllStatus('C');
        scwin.sleep(30).then(async function()  {
            gr_main6.refresh();
        });
		scwin.f_defaultCall();		// Key 값 수정 X
	}
	if(ds_main7.getRowCount() > 0){
        ds_main7.modifyAllStatus('C');
        scwin.sleep(30).then(async function()  {
            gr_main7.refresh();
        });
		scwin.f_defaultCallMain7();	// Key 값 수정 X
	}
	if(ds_main8.getRowCount() > 0){
        ds_main8.modifyAllStatus('C');
        scwin.sleep(30).then(async function()  {
            gr_main8.refresh();
        });
		scwin.f_defaultCallMain8();	// Key 값 수정 X
	}
};

//-------------------------------------------------------------------------
// 계약직 Grid 행추가 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_AddRow = async function () {
    var no = Number(this.opts.targetNo);

    if (txt_wrkIndictNo.getValue() == "") {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_018, ["작업지시번호","작업지시번호 생성"]); //"@이(가) 존재하지 않습니다.\n먼저 @을(를) 하십시오."
		return;
	}
	if(no == 6){	// DataSet no
        var nRow = ds_main6.getRowCount();
		ds_main6.insertRow(nRow);

		ds_main6.setCellData(nRow,"wrkIndictNo", txt_wrkIndictNo.getValue());	// Key 값 설정
		ds_main6.setCellData(nRow,"wrkStDt", scwin.parentObj.ica_wrkStDt.getValue());
		ds_main6.setCellData(nRow,"wrkStHh", scwin.parentObj.ed_wrkStHh.getValue());
		ds_main6.setCellData(nRow,"wrkEndDt", scwin.parentObj.ica_wrkEndDt.getValue());
		ds_main6.setCellData(nRow,"wrkEndHh", scwin.parentObj.ed_wrkEndHh.getValue());

        //to-do 로직엔 없으나 행추가시 기본적으로 0셋팅되는듯...
        ds_main6.setCellData(nRow,"assgnSeq", "0");

        gr_main6.setReadOnly("cell",nRow,"vehclShortCd",false);


		// 협력업체 거래처명이 '자사' 이면 거래처코드 수정 불가
		if("자사" == ds_main6.getCellData(nRow, "clntNm")){
            gr_main6.setReadOnly("cell",nRow,"clntNm",true);
            gr_main6.setReadOnly("cell",nRow,"clntNo",true);
		} else {
            gr_main6.setReadOnly("cell",nRow,"clntNm",false);
            gr_main6.setReadOnly("cell",nRow,"clntNo",false);
		}

		scwin.f_defaultCall();	// Key 값 수정 X

        ds_main6.setRowPosition(nRow);
	}
    else if(no == 7){	// DataSet no
        var nRow = ds_main7.getRowCount();
		ds_main7.insertRow(nRow);

		ds_main7.setCellData(nRow,"wrkIndictNo", txt_wrkIndictNo.getValue());	// Key 값 설정
		ds_main7.setCellData(nRow,"wrkStDt", scwin.parentObj.ica_wrkStDt.getValue());
		ds_main7.setCellData(nRow,"wrkStHh", scwin.parentObj.ed_wrkStHh.getValue());
		ds_main7.setCellData(nRow,"wrkEndDt", scwin.parentObj.ica_wrkEndDt.getValue());
		ds_main7.setCellData(nRow,"wrkEndHh", scwin.parentObj.ed_wrkEndHh.getValue());

        //to-do 로직엔 없으나 행추가시 기본적으로 0셋팅되는듯...
        ds_main7.setCellData(nRow,"assgnSeq", "0");
        ds_main7.setCellData(nRow,"reqHveqCnt", "0");
        ds_main7.setCellData(nRow,"inputHveqCnt", "0");

        gr_main7.setReadOnly("cell",nRow,"eqKndCd",false);
        gr_main7.setReadOnly("cell",nRow,"nesEqNrmCd",false);
        gr_main7.setReadOnly("cell",nRow,"clntNm",false);
        gr_main7.setReadOnly("cell",nRow,"clntNo",false);

		scwin.f_defaultCallMain7();	// Key 값 수정 X

        ds_main7.setRowPosition(nRow);
	}
    else if(no == 8){	// DataSet no
        var nRow = ds_main8.getRowCount();
        ds_main8.insertRow(nRow);

		ds_main8.setCellData(nRow,"wrkIndictNo", txt_wrkIndictNo.getValue());	// Key 값 설정

        //to-do 로직엔 없으나 행추가시 기본적으로 0셋팅되는듯...
        ds_main8.setCellData(nRow,"wrkImpleInputCnt", "0");

        gr_main8.setFocusedCell(nRow, "wrkImpleKndCd");

		scwin.f_defaultCallMain8();	// Key 값 수정 X
	}
};

//삭제
scwin.f_delete = async function () {
    var gubun = Number(this.opts.targetNo);
    if (gubun == 6) {
		var row = ds_main6.getRowPosition();

		if (ds_main6.getCellData(row,"assgnSeq") != "0") {
			await $c.gus.cfAlertMsg("해당 배정데이터에 대해 협력업체에서 이미 중기투입 등록하였으므로 삭제할 수 없습니다.");
			return;
		} else {
            //그리드에 매핑된 dataList의 row가 신규행이면 삭제하고 아니면 삭제마크처리.
            if(ds_main6.getRowStatus(row) == "C") {
                ds_main6.removeRow(row);
            } else {
                ds_main6.deleteRow(row);
            }
		}
	} else if (gubun == 7) {
		var row = ds_main7.getRowPosition();

		var yncheck = 0;
		for (var i=0; i<ds_main6.getRowCount(); i++) {
			if (ds_main6.getCellData(i,"clntNo") == ds_main7.getCellData(row,"clntNo")
			 && ds_main6.getCellData(i,"assgnSeq") == ds_main7.getCellData(row,"assgnSeq")) {
				yncheck = 1;
				break;
			}
		}

		if (yncheck == 1) {
			await $c.gus.cfAlertMsg("해당 배정데이터에 대해 협력업체에서 이미 중기투입 등록하였으므로 삭제할 수 없습니다.");
			return;
		} else {
			//ds_main7.DeleteMarked();
            ds_main7.deleteRow(row);
		}
	} else if (gubun == 8) {
        var row = ds_main8.getRowPosition();

        //그리드에 매핑된 dataList의 row가 신규행이면 삭제하고 아니면 삭제마크처리.
        if(ds_main8.getRowStatus(row) == "C") {
            ds_main8.removeRow(row);
        } else {
            ds_main8.deleteRow(row);
        }
    }
};

//취소 버튼 클릭시
scwin.f_cancel = function() {
    var gubun = Number(this.opts.targetNo);

    if (gubun == 6) {
        //그리드에 매핑된 dataList rowIdx 미존재시 이전에 클릭했던 rowIdx 셋팅처리.
        if(ds_main6.getRowPosition() == null) {
            ds_main6.setRowPosition(scwin.grid6_RowIdx);
        }
        $c.data.undoRow(ds_main6, "Y");
    } else if (gubun == 7) {
        //그리드에 매핑된 dataList rowIdx 미존재시 이전에 클릭했던 rowIdx 셋팅처리.
        if(ds_main7.getRowPosition() == null) {
            ds_main7.setRowPosition(scwin.grid7_RowIdx);
        }
        $c.data.undoRow(ds_main7, "Y");
    } else if (gubun == 8) {
        //그리드에 매핑된 dataList rowIdx 미존재시 이전에 클릭했던 rowIdx 셋팅처리.
        if(ds_main8.getRowPosition() == null) {
            ds_main8.setRowPosition(scwin.grid8_RowIdx);
        }
        $c.data.undoRow(ds_main8, "Y");
    }
};


//그리드에 매핑된 dataList rowStatus 가 변경시.
scwin.ds_main6_onrowstatuschange = function (info) {
    //해당 ROW 수정 후 삭제처리시
    if(info[0].oldRowStatus == "U") {
        if(info[0].newRowStatus == "D") {
            ds_main6.undoRow(info[0].rowIndex);
            ds_main6.deleteRow(info[0].rowIndex);
        }
    }
};

scwin.ds_main7_onrowstatuschange = function (info) {
    //해당 ROW 수정 후 삭제처리시
    if(info[0].oldRowStatus == "U") {
        if(info[0].newRowStatus == "D") {
            ds_main7.undoRow(info[0].rowIndex);
            ds_main7.deleteRow(info[0].rowIndex);
        }
    }
};

scwin.ds_main8_onrowstatuschange = function (info) {
    //해당 ROW 수정 후 삭제처리시
    if(info[0].oldRowStatus == "U") {
        if(info[0].newRowStatus == "D") {
            ds_main8.undoRow(info[0].rowIndex);
            ds_main8.deleteRow(info[0].rowIndex);
        }
    }
};
//-------------------------------------------------------------------------
//사번조회팝업
//-------------------------------------------------------------------------
scwin.f_openCommCdPopUp = async function (row, colid, gubun) {
    // 선언부
	var colidNm = "";
  	var rtnList = new Array();	
  	var pCode = "";
	var pName = "";
	var arrParam = new Array();

	if (colid == "drvStaffNo1"){
		colidNm = "drvStaffNm1";
	}else if (colid == "drvStaffNo2"){
		colidNm = "drvStaffNm2";
	}else if (colid == "drvStaffNo3"){
		colidNm = "drvStaffNm3";
	}else if (colid == "drvStaffNm1"){
		colidNm = "drvStaffNo1";
	}else if (colid == "drvStaffNm2"){
		colidNm = "drvStaffNo2";
	}else if (colid == "drvStaffNm3"){
		colidNm = "drvStaffNo3";
	}

	// 조회 조건 담기
	if (gubun == 1) {
    	pCode = ds_main6.getCellData(row,colid);
    } else {
    	pName = ds_main6.getCellData(row,colid);
    }
    ds_main6.setCellData(row,colidNm, "");

	arrParam[0] = pCode; //사번
	arrParam[1] = pName; //사원명
	arrParam[2] = scwin.parentObj.txt_hlobranCd.getValue(); //점소코드
	arrParam[3] = scwin.parentObj.txt_hlobranNm.getValue(); //점소명
	arrParam[4] = ''; //작업장코드
	arrParam[5] = '00,E';//직종  (전체)
	arrParam[6] = '01,D' //상세직종코드 (중기기사)
	arrParam[7] = ''; //직급
	arrParam[8] = scwin.parentObj.ica_wrkStDt.getValue();  //작업일
	arrParam[9] = 'Y'; //배치가능여부
	arrParam[10] = 'T'; //WINDOW CLOSE 여부

    var opts = {
        id : "smpPop", 
        popupName : "인력검색", //  팝업 타이틀에 표시
        type : "browserPopup"  // window popup , 해당 옵션이 없으면 layer popup
        ,modal : true
        , width : 1024
        , height : 600
    };

    let returnValue = await $c.win.openPopup("/ui/ds/op/rscconfirm/manpwrrscconfirm/op_103_01_10p.xml", opts, arrParam);

    if (returnValue != null && returnValue[1] != undefined) {
		if (gubun == 1) {
			ds_main6.setCellData(row,colid, returnValue[2]);	// 사번
			ds_main6.setCellData(row,colidNm, returnValue[3]);	// 이름
		} else {
			ds_main6.setCellData(row,colidNm, returnValue[2]);	// 사번
			ds_main6.setCellData(row,colid, returnValue[3]);	// 이름
		}
	} else {
        //to-do 공통코드는 지워야 함 그러나 다른 코드는??
        /*
        ds_main6.setCellData(row,colid, "");
        ds_main6.setCellData(row,colidNm, "");
        */
    }
};


