//-------------------------------------------------------------------------
// 작업시간 입력시 유효성체크
//-------------------------------------------------------------------------
scwin.f_validateWrkTime = async function () {

    for(i=0;i<ds_main6.getRowCount();i++){
		if (ds_main6.getCellData(i,"wrkStDt").length > 0 && ds_main6.getCellData(i,"wrkStDt") != scwin.parentObj.ica_wrkStDt.getValue().trim()) {
			await $c.gus.cfAlertMsg(MSG_CM_ERR_030 + "작업지시번호의 작업시작일자와 동일한 날만 가능합니다", ["작업시작일자"]);
            gr_main6.setFocusedCell(i, "wrkStDt");
			txt_hfocus.setValue("gr_main6");
			return false;
		}

   		if (ds_main6.getCellData(i,"wrkStDt").length != 8 || ds_main6.getCellData(i,"wrkEndDt").length != 8 || !$c.gus.cfIsAfterDate(ds_main6.getCellData(i,"wrkStDt"), ds_main6.getCellData(i,"wrkEndDt"), false)) {
   		    await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
			gr_main6.setFocusedCell(i, "wrkStDt");
            txt_hfocus.setValue("gr_main6");
   		    return false;
   		}

		if (ds_main6.getCellData(i,"wrkEndDt").length > 0 && (Number(ds_main6.getCellData(i,"wrkEndDt")) < Number(scwin.parentObj.ica_wrkStDt.getValue().trim()) || 
