//for=gr_main6 event=OnColumnPosChanged
//as-is: Grid에서 Column의 위치를변경한 후에 발생한다.
scwin.gr_main6_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {    

    //하위는 "for=ds_main6 event=OnRowPosChanged(row)" 로직임.
    gr_main6.removeHeaderClass("column33", "txt-blue");
    gr_main6.removeHeaderClass("column31", "txt-blue");
    gr_main6.removeHeaderClass("column33", "txt-red");
    gr_main6.removeHeaderClass("column31", "txt-red");

    if("자사" == ds_main6.getCellData(rowIndex, "clntNm")){
        gr_main6.setReadOnly("cell",rowIndex,"clntNm",true);
        gr_main6.setReadOnly("cell",rowIndex,"clntNo",true);

        gr_main6.setHeaderClass("column33", "txt-red");  //기사인원번호1
        gr_main6.setHeaderClass("column31", "txt-red");  //성명1
    } else {
        gr_main6.setReadOnly("cell",rowIndex,"clntNm",false);
        gr_main6.setReadOnly("cell",rowIndex,"clntNo",false);

        gr_main6.setHeaderClass("column33", "txt-blue");  //기사인원번호1
        gr_main6.setHeaderClass("column31", "txt-blue");  //성명1
    }
    if (rowIndex != scwin.gv_rowPos6) {
        scwin.gv_rowPos6 = rowIndex;
        scwin.f_defaultCall();	// Key 값 수정 X
    }

};

