//규격 셀 클릭하여 수정하기전 필터반영처리.
//셀값 수정(item 선택전) 혹은 셀클릭 이후는 afteredit 에서 필터 clear 처리필요.
scwin.gr_main7_onbeforeedit = function (rowIndex, columnIndex, value) {
    //규격 item 필터링 처리.
    if(columnIndex == 3) {
        var sFillterStr = ds_main7.getCellData(rowIndex, "eqKndCd");
        var fn_colFilter = function(cellData, tmpParam, rowIdx){
            if(cellData == sFillterStr){
                return true;
            }
            return false;   // return이 true인 경우 적용하고 false인 경우 넘김
        };

        ds_LkStepNo3.setColumnFilter( 
            {type:'func', colIndex:'upperCd', key:fn_colFilter, condition:'and'}
        );

        ds_LkStepNo3.reform();
    }
};


//for=gr_main7 event=OnExit 처리위한 로직2.(별도 함수 호출위한 로직)
//그리드 cell focus out 처리(상기 로직1의 변경되기전 정보가 없는 경우도 호출함.)
scwin.gr_main7_onafteredit = async function (rowIndex, columnIndex, value) {

    //규격 item 필터링 이후 타 row 의 규격 값 영향도 존재하므로 clear 처리.
    if(columnIndex == 3) {
        ds_LkStepNo3.clearFilter();
    }

    if(scwin.gr_main7_beforeCellChgInfos != undefined && scwin.gr_main7_beforeCellChgInfos != null && 
       scwin.gr_main7_beforeCellChgInfos != "" && Object.keys(scwin.gr_main7_beforeCellChgInfos).length > 0) {
        var cellRow = scwin.gr_main7_beforeCellChgInfos.rowIndex;
        var cellID = scwin.gr_main7_beforeCellChgInfos.colID;
        var cellOldVal = scwin.gr_main7_beforeCellChgInfos.oldValue;

        if(rowIndex == cellRow && gr_main7.getColumnID(columnIndex) == cellID) {
            let callObj;
            if(cellID == "eqKndCd") {
                callObj = udc_gr_main7_eqKndCd;
            } else if(cellID == "clntNm") {
                callObj = udc_gr_main7_clntNm;
            } else if(cellID == "clntNo") {
                callObj = udc_gr_main7_clntNo;
            }

            await scwin.gr_main7_OnExit(callObj, cellRow, cellID, cellOldVal);
        }
    }
};

scwin.gr_main7_OnExit = async function (callObj, row,colid,olddata) {
    scwin.udc_objNm = callObj.org_id;

    switch (colid) {
		case "eqKndCd":
			if(ds_main7.getCellData(row,colid) != olddata && ds_main7.getCellData(row,colid) != ""){
				var param1 = ds_main7.getCellData(row, "eqKndCd");
				var param2 = "";

                //초기화 처리.
                ds_main7.setCellData(row, "eqKndCd",""); //중기종류코드
                ds_main7.setCellData(row, "eqKndNm",""); //중기종류명
                ds_main7.setCellData(row, "eqNrmCd",""); //중기규격코드
                ds_main7.setCellData(row, "eqNrmNm",""); //중기규격

                callObj.setSelectId("retrieveClntHeavyMachineryInfo");

			 	await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc7,param1,param2,"T",null,null,null,null,null,420,500,null,null); // 중기LIST
			} else if (ds_main7.getCellData(row,colid) == "") {
				ds_main7.setCellData(row, "eqKndCd",""); //중기종류코드
                ds_main7.setCellData(row, "eqKndNm",""); //중기종류명
                ds_main7.setCellData(row, "eqNrmCd",""); //중기규격코드
                ds_main7.setCellData(row, "eqNrmNm",""); //중기규격
			}
			break;
		case "clntNm":
			if(ds_main7.getCellData(row,colid) != olddata && ds_main7.getCellData(row,colid) != ""){
				var param1 = ""//ds_main7.NameValue(row, "clntNo");
			 	var param2 = ds_main7.getCellData(row, "clntNm");

                //초기화 처리.
                ds_main7.setCellData(row, "clntNo","");
                ds_main7.setCellData(row, "clntNm","");

                callObj.setSelectId("retrieveHeavyMachineryClntInfo");

			 	await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc7,param1,param2,"T",null,null,null,null,null,450,500,null,null); // 중기협력업체	
			} else if (ds_main7.getCellData(row,colid) == "") {
				ds_main7.setCellData(row, "clntNo","");
                ds_main7.setCellData(row, "clntNm","");
			}
			break;
		case "clntNo":
			if(ds_main7.getCellData(row,colid) != olddata && ds_main7.getCellData(row,colid) != ""){
		 		var param1 = ds_main7.getCellData(row, "clntNo");
			 	var param2 = "";//ds_main7.NameValue(row, "clntNm");

                //초기화 처리.
                ds_main7.setCellData(row, "clntNo","");
                ds_main7.setCellData(row, "clntNm","");

                callObj.setSelectId("retrieveHeavyMachineryClntInfo");

			 	await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc7,param1,param2,"T",null,null,null,null,null,450,500,null,null); // 중기협력업체	
			} else if (ds_main7.getCellData(row,colid) == "") {
				ds_main7.setCellData(row, "clntNo","");
                ds_main7.setCellData(row, "clntNm","");
			}
			break;
	}
};

scwin.udc_AllInOne_callBackFunc7 = function (rtnList) {
    var row = gr_main7.getFocusedRowIndex();

    if(scwin.udc_objNm == "udc_gr_main7_eqKndCd") {
        if (rtnList != null && rtnList[1] != undefined && rtnList[1] != null && rtnList[1] != "") {
            ds_main7.setCellData(row, "eqKndCd", rtnList[0]); //중기종류코드
            ds_main7.setCellData(row, "eqKndNm", rtnList[1]); //중기종류명
            ds_main7.setCellData(row, "eqNrmCd", rtnList[2]); //중기규격코드
            ds_main7.setCellData(row, "eqNrmNm", rtnList[3]); //중기규격

            gr_main7.setFocusedCell(row, "nesEqNrmCd");
        }   

        if ( "N/" == ds_main7.getCellData(row, "eqKndCd") ){
            ds_main7.setCellData(row, "eqKndCd", "");
        }
    } else if(scwin.udc_objNm == "udc_gr_main7_clntNm") {
        $c.gus.cfSetGridReturnValue(rtnList, ds_main7, row, "clntNo", "clntNm");
    } else if(scwin.udc_objNm == "udc_gr_main7_clntNo") {
        $c.gus.cfSetGridReturnValue(rtnList, ds_main7, row, "clntNo", "clntNm");
    }
};

scwin.gr_main7_OnPopup = async function (rowIndex, colId, nowValue) {
    var colid = colId;
    var row = rowIndex;

    //중기
 	if (colid == "eqKndCd"){
 		var param1 = ds_main7.getCellData(row, "eqKndCd");
	 	var param2 = "";

        //초기화 처리.
        ds_main7.setCellData(row, "eqKndCd",""); //중기종류코드
        ds_main7.setCellData(row, "eqKndNm",""); //중기종류명
        ds_main7.setCellData(row, "eqNrmCd",""); //중기규격코드
        ds_main7.setCellData(row, "eqNrmNm",""); //중기규격

        scwin.udc_objNm = "udc_gr_main7_eqKndCd";

        udc_gr_main7_eqKndCd.setSelectId("retrieveClntHeavyMachineryInfo");

	 	await udc_gr_main7_eqKndCd.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc7,param1,param2,"F",null,null,null,null,null,420,500,null,null); // 중기LIST
 	}
    //협력업체명
    else if(colid == "clntNm") {
 		var param1 = ""//ds_main7.NameValue(row, "clntNo");
	 	var param2 = ds_main7.getCellData(row, "clntNm");

        //초기화 처리.
        ds_main7.setCellData(row, "clntNo","");
        ds_main7.setCellData(row, "clntNm","");

        scwin.udc_objNm = "udc_gr_main7_clntNm";

        udc_gr_main7_clntNm.setSelectId("retrieveHeavyMachineryClntInfo");

	 	await udc_gr_main7_clntNm.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc7,param1,param2,"F",null,null,null,null,null,450,500,null,null); // 중기협력업체
 	}
    //협력업체코드
    else if(colid == "clntNo") {
 		var param1 = ds_main7.getCellData(row, "clntNo");
	 	var param2 = "";//ds_main7.NameValue(row, "clntNm");

        //초기화 처리.
        ds_main7.setCellData(row, "clntNo","");
        ds_main7.setCellData(row, "clntNm","");

        scwin.udc_objNm = "udc_gr_main7_clntNo";

        udc_gr_main7_clntNo.setSelectId("retrieveHeavyMachineryClntInfo");

	 	await udc_gr_main7_clntNo.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc7,param1,param2,"F",null,null,null,null,null,450,500,null,null); // 중기협력업체
  	}
};

//for=gr_main7 event=OnColumnPosChanged
//as-is: Grid에서 Column의 위치를변경한 후에 발생한다.
scwin.gr_main7_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {

    //하위는 "for=ds_main7 event=OnRowPosChanged(row)" 에 관한 로직.
    if (rowIndex != scwin.gv_rowPos7) {
		scwin.gv_rowPos7 = rowIndex;
		scwin.f_defaultCallMain7();	// Key 값 수정 X
	}
};

scwin.gr_main7_oncellclick = function (rowIndex, columnIndex, columnId) {
    scwin.grid7_ColIdx = columnIndex;
    scwin.grid7_RowIdx = rowIndex;
};






//작업도구규격 item 필터링 처리위한 로직추가.
//작업도구규격 셀 클릭하여 수정하기전 필터반영처리.
//셀값 수정(item 선택전) 혹은 셀클릭 이후는 afteredit 에서 필터 clear 처리필요.
scwin.gr_main8_onbeforeedit = function (rowIndex, columnIndex, value) {
    //작업도구규격 item 필터링 처리.
    if(columnIndex == 2) {
        var sFillterStr = ds_main8.getCellData(rowIndex, "wrkImpleKndCd");
        var fn_colFilter = function(cellData, tmpParam, rowIdx){
            if(cellData == sFillterStr){
                return true;
            }
            return false;   // return이 true인 경우 적용하고 false인 경우 넘김
        };

        ds_LkStepNo.setColumnFilter( 
            {type:'func', colIndex:'upperCd', key:fn_colFilter, condition:'and'}
        );

        ds_LkStepNo.insertRow(0);
        ds_LkStepNo.setCellData(0, "name", "");
        ds_LkStepNo.setCellData(0, "code", "");

        ds_LkStepNo.reform();
    }
};

scwin.gr_main8_onafteredit = function (rowIndex, columnIndex, value) {
    //작업도구규격 item 필터링 이후 타 row 의 작업도구규격 값 영향도 존재하므로 clear 처리.
    if(columnIndex == 1 || columnIndex == 2) {
        ds_LkStepNo.clearFilter();

        if(columnIndex == 1) {
            ds_main8.setCellData(rowIndex, "wrkImpleNrmCd", "");
        }
    }
};

